def __init__(self, *args: QueryParamTypes, **kwargs: typing.Any) -> None:
    assert len(args) < 2, "Too many arguments."
    assert not (args and kwargs), "Cannot mix named and unnamed arguments."

    value = args[0] if args else kwargs

    if isinstance(value, str):
        items = parse_qsl(value)
    elif isinstance(value, QueryParams):
        items = value.multi_items()
    elif isinstance(value, list):
        items = value  # type: ignore
    else:
        # Handle mapping with potential sequence values
        items = []
        for k, v in value.items():  # type: ignore
            if isinstance(v, (list, tuple)) and not isinstance(v, (str, bytes)):
                # Expand sequence values into multiple items
                items.extend((k, item) for item in v)
            else:
                items.append((k, v))

    self._list = [(str(k), str_query_param(v)) for k, v in items]
    self._dict = {str(k): str_query_param(v) for k, v in items}

